INSERT INTO `kaoyan_info` (`title`, `source`, `source_url`, `publish_time`, `content`, `url`, `tags`, `urgency_level`, `category`, `province`, `school`, `major`, `degree_type`, `study_type`, `view_count`, `like_count`) VALUES
('北京大学2026年硕士研究生招生简章', '北京大学', 'https://www.pku.edu.cn', '2026-03-15 10:00:00', '<p>北京大学2026年硕士研究生招生简章已发布，计划招收硕士研究生5000名，其中学术型硕士3000名，专业型硕士2000名。报名时间为2026年9月24日至9月27日，考试时间为2026年12月21日至12月22日。</p><p>本次招生涵盖哲学、经济学、法学、教育学、文学、历史学、理学、工学、医学、管理学、艺术学等多个学科门类，欢迎广大考生报考。</p>', 'https://www.pku.edu.cn/zsxx/kyjszs/2026zsjz.html', '北京大学,硕士,招生简章', 2, 4, '北京', '北京大学', '计算机科学与技术', 1, 1, 1250, 89),
('清华大学2026年计算机科学与技术专业硕士招生简章', '清华大学', 'https://www.tsinghua.edu.cn', '2026-03-16 09:00:00', '<p>清华大学计算机科学与技术专业2026年计划招收硕士研究生150名，其中学术型硕士80名，专业型硕士70名。</p><p>报考条件：具有国家承认的本科学历，计算机相关专业背景优先。考试科目包括政治、英语一、数学一、计算机专业基础。</p>', 'https://www.tsinghua.edu.cn/zsxx/kyjszs/2026jsjzsjz.html', '清华大学,计算机,硕士', 2, 4, '北京', '清华大学', '计算机科学与技术', 1, 1, 980, 76),
('复旦大学2026年硕士研究生招生调剂公告', '复旦大学', 'https://www.fudan.edu.cn', '2026-03-10 14:00:00', '<p>复旦大学2026年硕士研究生招生调剂工作即将开始，部分专业有调剂名额，包括计算机科学与技术、软件工程、电子科学与技术等专业。</p><p>调剂条件：初试成绩达到国家线，且符合调入专业的报考条件。调剂系统将于2026年3月20日开放，请有调剂意向的考生及时关注。</p>', 'https://www.fudan.edu.cn/zsxx/kyjszs/2026tjgg.html', '复旦大学,调剂,硕士', 1, 1, '上海', '复旦大学', '计算机科学与技术', 1, 1, 750, 58),
('上海交通大学2026年硕士研究生扩招公告', '上海交通大学', 'https://www.sjtu.edu.cn', '2026-03-08 11:00:00', '<p>上海交通大学2026年硕士研究生招生计划有所增加，部分专业扩招10%-20%，包括人工智能、大数据、生物医药等热门专业。</p><p>扩招原因：为满足国家战略需求，培养更多高层次人才。具体扩招专业及名额请查看学校官网。</p>', 'https://www.sjtu.edu.cn/zsxx/kyjszs/2026kzgg.html', '上海交通大学,扩招,硕士', 1, 2, '上海', '上海交通大学', '人工智能', 1, 1, 620, 45),
('浙江大学2026年硕士研究生复试分数线', '浙江大学', 'https://www.zju.edu.cn', '2026-03-05 16:00:00', '<p>浙江大学2026年硕士研究生复试分数线已公布，学术型硕士复试分数线：哲学320分，经济学360分，法学335分，教育学330分，文学350分，历史学320分，理学320分，工学310分，医学330分，管理学340分，艺术学340分。</p><p>专业型硕士复试分数线：金融365分，应用统计350分，税务350分，国际商务350分，保险340分，资产评估340分，审计220分，法律330分，社会工作320分，教育330分，体育300分，汉语国际教育320分，应用心理320分，翻译350分，新闻与传播350分，出版340分，文物与博物馆320分，建筑学310分，工程310分，城市规划310分，农业300分，兽医300分，风景园林310分，林业300分，临床医学330分，口腔医学330分，公共卫生330分，护理320分，药学320分，中药学320分，工商管理170分，公共管理175分，会计190分，旅游管理170分，图书情报190分，工程管理170分，艺术340分。</p>', 'https://www.zju.edu.cn/zsxx/kyjszs/2026fsscore.html', '浙江大学,复试线,硕士', 2, 3, '浙江', '浙江大学', '计算机科学与技术', 1, 1, 1050, 82),
('中国人民大学2026年硕士研究生招生简章', '中国人民大学', 'https://www.ruc.edu.cn', '2026-03-12 10:00:00', '<p>中国人民大学2026年硕士研究生招生简章已发布，计划招收硕士研究生4500名，其中学术型硕士2500名，专业型硕士2000名。</p><p>报名时间为2026年9月24日至9月27日，考试时间为2026年12月21日至12月22日。欢迎广大考生报考。</p>', 'https://www.ruc.edu.cn/zsxx/kyjszs/2026zsjz.html', '中国人民大学,硕士,招生简章', 2, 4, '北京', '中国人民大学', '金融学', 1, 1, 890, 67),
('同济大学2026年硕士研究生招生调剂公告', '同济大学', 'https://www.tongji.edu.cn', '2026-03-09 14:00:00', '<p>同济大学2026年硕士研究生招生调剂工作即将开始，部分专业有调剂名额，包括土木工程、机械工程、电子科学与技术等专业。</p><p>调剂条件：初试成绩达到国家线，且符合调入专业的报考条件。调剂系统将于2026年3月20日开放，请有调剂意向的考生及时关注。</p>', 'https://www.tongji.edu.cn/zsxx/kyjszs/2026tjgg.html', '同济大学,调剂,硕士', 1, 1, '上海', '同济大学', '土木工程', 1, 1, 580, 42),
('北京航空航天大学2026年硕士研究生扩招公告', '北京航空航天大学', 'https://www.buaa.edu.cn', '2026-03-07 11:00:00', '<p>北京航空航天大学2026年硕士研究生招生计划有所增加，部分专业扩招15%-25%，包括航空航天、人工智能、计算机等热门专业。</p><p>扩招原因：为满足国家战略需求，培养更多高层次人才。具体扩招专业及名额请查看学校官网。</p>', 'https://www.buaa.edu.cn/zsxx/kyjszs/2026kzgg.html', '北京航空航天大学,扩招,硕士', 1, 2, '北京', '北京航空航天大学', '航空航天', 1, 1, 650, 48),
('华中科技大学2026年硕士研究生复试分数线', '华中科技大学', 'https://www.hust.edu.cn', '2026-03-04 16:00:00', '<p>华中科技大学2026年硕士研究生复试分数线已公布，学术型硕士复试分数线：哲学320分，经济学355分，法学330分，教育学325分，文学345分，历史学315分，理学315分，工学305分，医学325分，管理学335分，艺术学335分。</p><p>专业型硕士复试分数线：金融360分，应用统计345分，税务345分，国际商务345分，保险335分，资产评估335分，审计215分，法律325分，社会工作315分，教育325分，体育295分，汉语国际教育315分，应用心理315分，翻译345分，新闻与传播345分，出版335分，文物与博物馆315分，建筑学305分，工程305分，城市规划305分，农业295分，兽医295分，风景园林305分，林业295分，临床医学325分，口腔医学325分，公共卫生325分，护理315分，药学315分，中药学315分，工商管理165分，公共管理170分，会计185分，旅游管理165分，图书情报185分，工程管理165分，艺术335分。</p>', 'https://www.hust.edu.cn/zsxx/kyjszs/2026fsscore.html', '华中科技大学,复试线,硕士', 2, 3, '湖北', '华中科技大学', '计算机科学与技术', 1, 1, 920, 71),
('中山大学2026年硕士研究生招生简章', '中山大学', 'https://www.sysu.edu.cn', '2026-03-13 10:00:00', '<p>中山大学2026年硕士研究生招生简章已发布，计划招收硕士研究生4000名，其中学术型硕士2000名，专业型硕士2000名。</p><p>报名时间为2026年9月24日至9月27日，考试时间为2026年12月21日至12月22日。欢迎广大考生报考。</p>', 'https://www.sysu.edu.cn/zsxx/kyjszs/2026zsjz.html', '中山大学,硕士,招生简章', 2, 4, '广东', '中山大学', '计算机科学与技术', 1, 1, 850, 64);
