INSERT INTO `kaogong_info` (`title`, `source`, `source_url`, `publish_time`, `content`, `url`, `tags`, `urgency_level`, `category`, `province`, `position_type`, `major`, `education`, `is_fresh_graduate`, `is_unlimited`, `competition_ratio`, `view_count`, `like_count`) VALUES
('中央机关及其直属机构2026年度考试录用公务员公告', '国家公务员局', 'http://www.scs.gov.cn', '2026-03-10 09:00:00', '<p>中央机关及其直属机构2026年度考试录用公务员工作即将开始，计划招录3.5万名公务员，其中中央机关招录1.2万名，直属机构招录2.3万名。</p><p>报名时间为2026年10月15日至10月24日，公共科目笔试时间为2026年11月23日。</p><p>本次招录职位涵盖中央机关、中央国家行政机关省级以下直属机构、中央国家行政机关参照公务员法管理事业单位等多个类别，欢迎广大考生报考。</p>', 'http://www.scs.gov.cn/xxgk2020/fdzdgknr/202603/t20260310_105123.html', '国考,公告,公务员', 3, 1, '全国', '综合管理', '不限', '本科及以上', 0, 0, 56.8, 2500, 189),
('2026年北京市公务员考试公告', '北京市人力资源和社会保障局', 'https://rsj.beijing.gov.cn', '2026-03-08 10:00:00', '<p>2026年北京市公务员考试公告已发布，计划招录3000名公务员。</p><p>报名时间为2026年11月1日至11月5日，笔试时间为2026年12月15日。</p><p>本次招录职位涵盖北京市各级机关，包括市级机关、区县级机关、乡镇街道机关等，欢迎广大考生报考。</p>', 'https://rsj.beijing.gov.cn/xxgk/zcwj/202603/t20260308_265432.html', '北京,省考,公务员', 2, 1, '北京', '综合管理', '不限', '本科及以上', 0, 0, 42.5, 1800, 145),
('2026年上海市公务员考试职位表', '上海市人力资源和社会保障局', 'https://rsj.sh.gov.cn', '2026-03-07 14:00:00', '<p>2026年上海市公务员考试职位表已发布，本次考试共招录2500名公务员，涉及市级机关、区县级机关、乡镇街道机关等多个层级。</p><p>职位表包含职位名称、招录人数、报考条件、工作地点等信息，考生可根据自身情况选择合适的职位报考。</p>', 'https://rsj.sh.gov.cn/xxgk/zcwj/202603/t20260307_345678.html', '上海,省考,职位表', 2, 2, '上海', '综合管理', '不限', '本科及以上', 0, 0, 38.2, 1500, 118),
('